    73→func newDefaultPolicy(numCounters, maxCost int64) *defaultPolicy {
    74→	p := &defaultPolicy{
    75→		admit:   newTinyLFU(numCounters),
    76→		evict:   newSampledLFU(maxCost),
    77→		itemsCh: make(chan []uint64, 3),
    78→		stop:    make(chan struct{}),
    79→	}
    80→	go p.processItems()
    81→	return p
    82→}
