   121→func (p *defaultPolicy) Add(key uint64, cost int64) ([]*item, bool) {
   122→	p.Lock()
   123→	defer p.Unlock()
   124→	// can't add an item bigger than entire cache
   125→	if cost > p.evict.maxCost {
   126→		return nil, false
   127→	}
   128→	// we don't need to go any further if the item is already in the cache
   129→	if has := p.evict.updateIfHas(key, cost); has {
   130→		return nil, true
   131→	}
   132→	// if we got this far, this key doesn't exist in the cache
   133→	//
   134→	// calculate the remaining room in the cache (usually bytes)
   135→	room := p.evict.roomLeft(cost)
   136→	if room >= 0 {
   137→		// there's enough room in the cache to store the new item without
   138→		// overflowing, so we can do that now and stop here
   139→		p.evict.add(key, cost)
   140→		return nil, true
   141→	}
   142→	// incHits is the hit count for the incoming item
   143→	incHits := p.admit.Estimate(key)
   144→	// sample is the eviction candidate pool to be filled via random sampling
   145→	//
   146→	// TODO: perhaps we should use a min heap here. Right now our time
   147→	// complexity is N for finding the min. Min heap should bring it down to
   148→	// O(lg N).
   149→	sample := make([]*policyPair, 0, lfuSample)
   150→	// as items are evicted they will be appended to victims
   151→	victims := make([]*item, 0)
   152→	// delete victims until there's enough space or a minKey is found that has
   153→	// more hits than incoming item.
   154→	for ; room < 0; room = p.evict.roomLeft(cost) {
   155→		// fill up empty slots in sample
   156→		sample = p.evict.fillSample(sample)
   157→		// find minimally used item in sample
   158→		minKey, minHits, minId, minCost := uint64(0), int64(math.MaxInt64), 0, int64(0)
   159→		for i, pair := range sample {
   160→			// look up hit count for sample key
   161→			if hits := p.admit.Estimate(pair.key); hits < minHits {
   162→				minKey, minHits, minId, minCost = pair.key, hits, i, pair.cost
   163→			}
   164→		}
   165→		// if the incoming item isn't worth keeping in the policy, reject.
   166→		if incHits < minHits {
   167→			p.metrics.add(rejectSets, key, 1)
   168→			return victims, false
   169→		}
   170→		// delete the victim from metadata
   171→		p.evict.del(minKey)
   172→		// delete the victim from sample
   173→		sample[minId] = sample[len(sample)-1]
   174→		sample = sample[:len(sample)-1]
   175→		// store victim in evicted victims slice
   176→		victims = append(victims, &item{
   177→			key:  minKey,
   178→			cost: minCost,
   179→		})
   180→	}
   181→	p.evict.add(key, cost)
   182→	return victims, true
   183→}
