   234→// sampledLFU is an eviction helper storing key-cost pairs.
   235→type sampledLFU struct {
   236→	keyCosts map[uint64]int64
   237→	maxCost  int64
   238→	used     int64
   239→	metrics  *Metrics
   240→}
   241→
   242→func newSampledLFU(maxCost int64) *sampledLFU {
   243→	return &sampledLFU{
   244→		keyCosts: make(map[uint64]int64),
   245→		maxCost:  maxCost,
   246→	}
   247→}
   248→
   249→func (p *sampledLFU) roomLeft(cost int64) int64 {
   250→	return p.maxCost - (p.used + cost)
   251→}
   252→
   253→func (p *sampledLFU) fillSample(in []*policyPair) []*policyPair {
   254→	if len(in) >= lfuSample {
   255→		return in
   256→	}
   257→	for key, cost := range p.keyCosts {
   258→		in = append(in, &policyPair{key, cost})
   259→		if len(in) >= lfuSample {
   260→			return in
   261→		}
   262→	}
   263→	return in
   264→}
   265→
   266→func (p *sampledLFU) del(key uint64) {
   267→	cost, ok := p.keyCosts[key]
   268→	if !ok {
   269→		return
   270→	}
   271→	p.metrics.add(keyEvict, key, 1)
   272→	p.metrics.add(costEvict, key, uint64(cost))
   273→	p.used -= cost
   274→	delete(p.keyCosts, key)
   275→}
   276→
   277→func (p *sampledLFU) add(key uint64, cost int64) {
   278→	p.metrics.add(keyAdd, key, 1)
   279→	p.metrics.add(costAdd, key, uint64(cost))
   280→	p.keyCosts[key] = cost
   281→	p.used += cost
   282→}
   283→
   284→func (p *sampledLFU) updateIfHas(key uint64, cost int64) bool {
   285→	if prev, found := p.keyCosts[key]; found {
   286→		// update the cost of an existing key, but don't worry about evicting,
   287→		// evictions will be handled the next time a new item is added
   288→		p.metrics.add(keyUpdate, key, 1)
   289→		p.used += cost - prev
   290→		p.keyCosts[key] = cost
   291→		return true
   292→	}
   293→	return false
   294→}
   295→
   296→func (p *sampledLFU) clear() {
   297→	p.used = 0
   298→	p.keyCosts = make(map[uint64]int64)
   299→}
