   301→// tinyLFU is an admission helper that keeps track of access frequency using
   302→// tiny (4-bit) counters in the form of a count-min sketch.
   303→// tinyLFU is NOT thread safe.
   304→type tinyLFU struct {
   305→	freq    *cmSketch
   306→	door    *z.Bloom
   307→	incrs   int64
   308→	resetAt int64
   309→}
   310→
   311→func newTinyLFU(numCounters int64) *tinyLFU {
   312→	return &tinyLFU{
   313→		freq:    newCmSketch(numCounters),
   314→		door:    z.NewBloomFilter(float64(numCounters), 0.01),
   315→		resetAt: numCounters,
   316→	}
   317→}
   318→
   319→func (p *tinyLFU) Push(keys []uint64) {
   320→	for _, key := range keys {
   321→		p.Increment(key)
   322→	}
   323→}
   324→
   325→func (p *tinyLFU) Estimate(key uint64) int64 {
   326→	hits := p.freq.Estimate(key)
   327→	if p.door.Has(key) {
   328→		hits += 1
   329→	}
   330→	return hits
   331→}
   332→
   333→func (p *tinyLFU) Increment(key uint64) {
   334→	// flip doorkeeper bit if not already
   335→	if added := p.door.AddIfNotHas(key); !added {
   336→		// increment count-min counter if doorkeeper bit is already set.
   337→		p.freq.Increment(key)
   338→	}
   339→	p.incrs++
   340→	if p.incrs >= p.resetAt {
   341→		p.reset()
   342→	}
   343→}
   344→
   345→func (p *tinyLFU) reset() {
   346→	// Zero out incrs.
   347→	p.incrs = 0
   348→	// clears doorkeeper bits
   349→	p.door.Clear()
   350→	// halves count-min counters
   351→	p.freq.Reset()
   352→}
   353→
   354→func (p *tinyLFU) clear() {
   355→	p.incrs = 0
   356→	p.door.Clear()
   357→	p.freq.Clear()
   358→}
