    23→// store is the interface fulfilled by all hash map implementations in this
    24→// file. Some hash map implementations are better suited for certain data
    25→// distributions than others, so this allows us to abstract that out for use
    26→// in Ristretto.
    27→//
    28→// Every store is safe for concurrent usage.
    29→type store interface {
    30→	// Get returns the value associated with the key parameter.
    31→	Get(uint64) (interface{}, bool)
    32→	// Set adds the key-value pair to the Map or updates the value if it's
    33→	// already present.
    34→	Set(uint64, interface{})
    35→	// Del deletes the key-value pair from the Map.
    36→	Del(uint64)
    37→	// Clear clears all contents of the store.
    38→	Clear()
    39→	// Update attempts to update the key with a new value and returns true if
    40→	// successful.
    41→	Update(uint64, interface{}) bool
    42→}
