    51→type shardedMap struct {
    52→	shards []*lockedMap
    53→}
    54→
    55→func newShardedMap() *shardedMap {
    56→	sm := &shardedMap{shards: make([]*lockedMap, int(numShards))}
    57→	for i := range sm.shards {
    58→		sm.shards[i] = newLockedMap()
    59→	}
    60→	return sm
    61→}
