    72→
    73→func (sm *shardedMap) Del(key uint64) {
    74→	idx := key % numShards
    75→	sm.shards[idx].Del(key)
    76→}
    77→
    78→func (sm *shardedMap) Clear() {
    79→	for i := uint64(0); i < numShards; i++ {
    80→		sm.shards[i].Clear()
    81→	}
    82→}
    83→
    84→func (sm *shardedMap) Update(key uint64, value interface{}) bool {
    85→	idx := key % numShards
